import { app, BrowserWindow, ipcMain, screen, globalShortcut } from 'electron'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import db from './db'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

// The built directory structure
//
// Γö£ΓöÇΓö¼ΓöÇΓö¼ dist
// Γöé Γöé ΓööΓöÇΓöÇ index.html
// Γöé Γöé
// Γöé Γö£ΓöÇΓö¼ dist-electron
// Γöé Γöé Γö£ΓöÇΓöÇ main.js
// Γöé Γöé ΓööΓöÇΓöÇ preload.mjs
// Γöé
process.env.APP_ROOT = path.join(__dirname, '..')

// ≡ƒÜº Use ['ENV_NAME'] avoid vite:define plugin - Vite@2.x
export const VITE_DEV_SERVER_URL = process.env['VITE_DEV_SERVER_URL']
export const MAIN_DIST = path.join(process.env.APP_ROOT, 'dist-electron')
export const RENDERER_DIST = path.join(process.env.APP_ROOT, 'dist')

process.env.VITE_PUBLIC = VITE_DEV_SERVER_URL ? path.join(process.env.APP_ROOT, 'public') : RENDERER_DIST

let win: BrowserWindow | null

function createWindow() {
  win = new BrowserWindow({
    width: 1200,
    height: 800,
    icon: path.join(process.env.VITE_PUBLIC, 'favicon.ico'),
    autoHideMenuBar: true,
    transparent: true,
    frame: false,
    hasShadow: false,
    webPreferences: {
      preload: path.join(__dirname, 'preload.mjs'),
      backgroundThrottling: false,
    },
  })

  win.on('maximize', () => {
    win?.webContents.send('window-maximized', true)
  })

  win.on('unmaximize', () => {
    win?.webContents.send('window-maximized', false)
  })

  // Test active push message to Renderer-process.
  win.webContents.on('did-finish-load', () => {
    win?.webContents.send('main-process-message', (new Date).toLocaleString())
    win?.webContents.send('window-maximized', win?.isMaximized())
  })

  if (VITE_DEV_SERVER_URL) {
    win.loadURL(VITE_DEV_SERVER_URL)
  } else {
    // win.loadFile('dist/index.html')
    win.loadFile(path.join(RENDERER_DIST, 'index.html'))
  }
}

// Quit when all windows are closed, except on macOS. There, it's common
// for applications and their menu bar to stay active until the user quits
// explicitly with Cmd + Q.
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
    win = null
  }
})

app.on('activate', () => {
  // On OS X it's common to re-create a window in the app when the
  // dock icon is clicked and there are no other windows open.
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow()
  }
})

app.whenReady().then(() => {
  // Set the App User Model ID for Windows to ensure the correct icon is displayed in the taskbar
  if (process.platform === 'win32') {
    app.setAppUserModelId('com.murtaza.mos');
  }

  // Handle permission requests for media (audio/video capture)
  const { session, desktopCapturer } = require('electron') as typeof import('electron');
  session.defaultSession.setPermissionRequestHandler((_webContents: Electron.WebContents, permission: string, callback: (granted: boolean) => void) => {
    // Allow audio and video capture for system audio loopback
    if (permission === 'media' || permission === 'audioCapture' || permission === 'videoCapture') {
      callback(true);
    } else {
      callback(true); // Allow all other permissions too
    }
  });

  // Also set display media request handler for screen/audio capture
  session.defaultSession.setDisplayMediaRequestHandler((_request: unknown, callback: (streams: { video: Electron.DesktopCapturerSource; audio: 'loopback' }) => void) => {
    // Auto-select the primary screen
    desktopCapturer.getSources({ types: ['screen'] }).then((sources: Electron.DesktopCapturerSource[]) => {
      if (sources.length > 0) {
        callback({ video: sources[0], audio: 'loopback' });
      }
    });
  });

  // IPC Handlers
  ipcMain.handle('get-tasks', () => {
    return db.prepare('SELECT * FROM tasks').all();
  });

  ipcMain.handle('add-task', (_, task) => {
    const stmt = db.prepare('INSERT INTO tasks (title, description, dueDate, difficulty, statTarget, labels, repeatingTaskId, subtasks) VALUES (@title, @description, @dueDate, @difficulty, @statTarget, @labels, @repeatingTaskId, @subtasks)');
    return stmt.run({
      ...task,
      statTarget: JSON.stringify(task.statTarget),
      labels: JSON.stringify(task.labels),
      repeatingTaskId: task.repeatingTaskId || null,
      subtasks: JSON.stringify(task.subtasks || [])
    });
  });

  ipcMain.handle('update-task', (_, task) => {
    const stmt = db.prepare('UPDATE tasks SET title = @title, description = @description, dueDate = @dueDate, difficulty = @difficulty, isComplete = @isComplete, statTarget = @statTarget, labels = @labels, subtasks = @subtasks, completedAt = @completedAt WHERE id = @id');
    return stmt.run({
      ...task,
      completedAt: task.completedAt || null,
      statTarget: JSON.stringify(task.statTarget),
      labels: JSON.stringify(task.labels),
      subtasks: JSON.stringify(task.subtasks || [])
    });
  });

  ipcMain.handle('delete-task', (_, id) => {
    return db.prepare('DELETE FROM tasks WHERE id = ?').run(id);
  });

  // Sessions
  ipcMain.handle('add-session', (_, session) => {
    const stmt = db.prepare('INSERT INTO sessions (taskId, startTime, endTime, duration_minutes, dateLogged) VALUES (@taskId, @startTime, @endTime, @duration_minutes, @dateLogged)');
    return stmt.run(session);
  });

  ipcMain.handle('get-sessions-by-date', (_, date) => {
    return db.prepare('SELECT * FROM sessions WHERE dateLogged = ?').all(date);
  });

  ipcMain.handle('get-sessions-range', (_, { startDate, endDate }) => {
    return db.prepare('SELECT * FROM sessions WHERE dateLogged BETWEEN ? AND ?').all(startDate, endDate);
  });

  ipcMain.handle('get-sessions-by-task', (_, taskId) => {
    return db.prepare('SELECT * FROM sessions WHERE taskId = ? ORDER BY startTime DESC').all(taskId);
  });
  // Stats
  ipcMain.handle('get-stats', () => {
    return db.prepare('SELECT * FROM stats').all();
  });

  ipcMain.handle('update-stat', (_, { statName, currentXP, currentLevel }) => {
    return db.prepare('UPDATE stats SET currentXP = ?, currentLevel = ? WHERE statName = ?').run(currentXP, currentLevel, statName);
  });

  ipcMain.handle('add-stat', (_, statName) => {
    return db.prepare('INSERT INTO stats (statName) VALUES (?)').run(statName);
  });

  ipcMain.handle('delete-stat', (_, statName) => {
    return db.prepare('DELETE FROM stats WHERE statName = ?').run(statName);
  });

  ipcMain.handle('rename-stat', (_, { oldName, newName }) => {
    const transaction = db.transaction(() => {
      db.prepare('UPDATE stats SET statName = ? WHERE statName = ?').run(newName, oldName);

      const tasks = db.prepare('SELECT id, statTarget FROM tasks').all();
      const updateTask = db.prepare('UPDATE tasks SET statTarget = ? WHERE id = ?');

      tasks.forEach((task: any) => {
        let targets: string[] = [];
        try {
          targets = JSON.parse(task.statTarget || '[]');
        } catch (e) {
          targets = [];
        }

        if (Array.isArray(targets) && targets.includes(oldName)) {
          targets = targets.map(t => t === oldName ? newName : t);
          updateTask.run(JSON.stringify(targets), task.id);
        }
      });
    });
    return transaction();
  });

  // Daily Log
  ipcMain.handle('get-daily-log', (_, date) => {
    return db.prepare('SELECT * FROM daily_logs WHERE date = ?').get(date);
  });

  ipcMain.handle('save-daily-log', (_, log) => {
    const stmt = db.prepare('INSERT OR REPLACE INTO daily_logs (date, journalEntry, prayersCompleted) VALUES (@date, @journalEntry, @prayersCompleted)');
    return stmt.run(log);
  });

  ipcMain.handle('save-journal-entry', (_, { date, entry }) => {
    const row = db.prepare('SELECT * FROM daily_logs WHERE date = ?').get(date);
    if (row) {
      return db.prepare('UPDATE daily_logs SET journalEntry = ? WHERE date = ?').run(entry, date);
    } else {
      return db.prepare('INSERT INTO daily_logs (date, journalEntry, prayersCompleted) VALUES (?, ?, "{}")').run(date, entry);
    }
  });

  // Dev Items
  ipcMain.handle('get-dev-items', () => {
    return db.prepare('SELECT * FROM dev_items').all();
  });

  ipcMain.handle('add-dev-item', (_, text) => {
    return db.prepare('INSERT INTO dev_items (text) VALUES (?)').run(text);
  });

  ipcMain.handle('toggle-dev-item', (_, { id, isComplete }) => {
    return db.prepare('UPDATE dev_items SET isComplete = ? WHERE id = ?').run(isComplete, id);
  });

  ipcMain.handle('delete-dev-item', (_, id) => {
    return db.prepare('DELETE FROM dev_items WHERE id = ?').run(id);
  });

  // Repeating Tasks
  ipcMain.handle('get-repeating-tasks', () => {
    return db.prepare('SELECT * FROM repeating_tasks').all();
  });

  ipcMain.handle('add-repeating-task', (_, task) => {
    const stmt = db.prepare('INSERT INTO repeating_tasks (title, description, difficulty, statTarget, labels, repeatType, repeatDays, isActive, lastGeneratedDate, subtasks, streak) VALUES (@title, @description, @difficulty, @statTarget, @labels, @repeatType, @repeatDays, @isActive, @lastGeneratedDate, @subtasks, @streak)');
    return stmt.run({
      ...task,
      lastGeneratedDate: task.lastGeneratedDate || null,
      statTarget: JSON.stringify(task.statTarget),
      labels: JSON.stringify(task.labels),
      repeatDays: JSON.stringify(task.repeatDays),
      subtasks: JSON.stringify(task.subtasks || []),
      streak: task.streak || 0
    });
  });

  ipcMain.handle('update-repeating-task', (_, task) => {
    const stmt = db.prepare('UPDATE repeating_tasks SET title = @title, description = @description, difficulty = @difficulty, statTarget = @statTarget, labels = @labels, repeatType = @repeatType, repeatDays = @repeatDays, isActive = @isActive, lastGeneratedDate = @lastGeneratedDate, subtasks = @subtasks, streak = @streak WHERE id = @id');
    return stmt.run({
      ...task,
      lastGeneratedDate: task.lastGeneratedDate || null,
      statTarget: JSON.stringify(task.statTarget),
      labels: JSON.stringify(task.labels),
      repeatDays: JSON.stringify(task.repeatDays),
      subtasks: JSON.stringify(task.subtasks || []),
      streak: task.streak || 0
    });
  });

  ipcMain.handle('delete-repeating-task', (_, id) => {
    return db.prepare('DELETE FROM repeating_tasks WHERE id = ?').run(id);
  });

  // Notes Mode
  ipcMain.handle('get-subjects', () => {
    return db.prepare('SELECT * FROM subjects ORDER BY orderIndex ASC, id ASC').all();
  });

  ipcMain.handle('create-subject', (_, subject) => {
    const stmt = db.prepare('INSERT INTO subjects (title, color, createdAt, orderIndex) VALUES (@title, @color, @createdAt, @orderIndex)');
    return stmt.run({
      ...subject,
      createdAt: new Date().toISOString()
    });
  });

  ipcMain.handle('update-subject', (_, subject) => {
    const stmt = db.prepare('UPDATE subjects SET title = @title, color = @color WHERE id = @id');
    return stmt.run(subject);
  });

  ipcMain.handle('delete-subject', (_, id) => {
    return db.prepare('DELETE FROM subjects WHERE id = ?').run(id);
  });

  ipcMain.handle('get-notes', (_, subjectId) => {
    return db.prepare('SELECT * FROM notes WHERE subjectId = ? ORDER BY updatedAt DESC').all(subjectId);
  });

  ipcMain.handle('create-note', (_, note) => {
    const stmt = db.prepare('INSERT INTO notes (subjectId, title, content, createdAt, updatedAt) VALUES (@subjectId, @title, @content, @createdAt, @updatedAt)');
    const now = new Date().toISOString();
    return stmt.run({
      ...note,
      createdAt: now,
      updatedAt: now
    });
  });

  ipcMain.handle('update-note', (_, note) => {
    const stmt = db.prepare('UPDATE notes SET title = @title, content = @content, updatedAt = @updatedAt WHERE id = @id');
    return stmt.run({
      ...note,
      updatedAt: new Date().toISOString()
    });
  });

  ipcMain.handle('delete-note', (_, id) => {
    return db.prepare('DELETE FROM notes WHERE id = ?').run(id);
  });

  ipcMain.handle('search-notes', (_, query) => {
    const likeQuery = `%${query}%`;
    return db.prepare(`
      SELECT n.*, s.title as subjectTitle, s.color as subjectColor 
      FROM notes n 
      JOIN subjects s ON n.subjectId = s.id 
      WHERE n.title LIKE ? OR n.content LIKE ? 
      ORDER BY n.updatedAt DESC
    `).all(likeQuery, likeQuery);
  });

  ipcMain.on('minimize-window', () => {
    win?.setAlwaysOnTop(false);
    win?.minimize();
  });

  ipcMain.on('maximize-window', () => {
    if (win?.isMaximized()) {
      win?.unmaximize();
    } else {
      win?.maximize();
    }
  });

  ipcMain.on('toggle-pin', (_, shouldPin) => {
    win?.setAlwaysOnTop(shouldPin);
  });

  ipcMain.on('set-taskbar-mode', (_, enable) => {
    if (enable) {
      const currentBounds = win?.getBounds();
      const display = currentBounds ? screen.getDisplayMatching(currentBounds) : screen.getPrimaryDisplay();
      const { width, height, x, y } = display.bounds;
      const taskbarHeight = 48;

      // Position at the very bottom of the screen, covering the taskbar if necessary
      win?.setSize(width, taskbarHeight);
      win?.setPosition(x, y + height - taskbarHeight);
      win?.setAlwaysOnTop(true, 'screen-saver'); // Ensure it stays on top of everything
    } else {
      win?.setSize(1200, 800);
      win?.center();
      win?.setAlwaysOnTop(false);
    }
  });

  ipcMain.on('close-window', () => {
    win?.close();
  });

  ipcMain.on('set-ignore-mouse-events', (event, ignore, options) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    win?.setIgnoreMouseEvents(ignore, options)
  })

  ipcMain.on('set-overlay-mode', (_, enable) => {
    if (enable) {
      const display = screen.getPrimaryDisplay();
      const { x, y, width, height } = display.bounds; // Use bounds to cover entire screen including taskbar
      // Ideally use setContentProtection or similar if we wanted to be super aggressive, but alwaysOnTop is usually enough.
      win?.setBounds({ x, y, width, height });
      win?.setAlwaysOnTop(true, 'screen-saver');
      // Default to "click-through" so user can click other apps
      win?.setIgnoreMouseEvents(true, { forward: true });
    } else {
      win?.setSize(1200, 800);
      win?.center();
      win?.setAlwaysOnTop(false);
      win?.setIgnoreMouseEvents(false);
    }
  });

  // Global Shortcut for Notes Mode
  globalShortcut.register('CommandOrControl+`', () => {
    win?.webContents.send('toggle-notes-mode');
    // If minimized, restore? Or just toggle logic in renderer? 
    // The user requirement implies opening it up.
    if (win?.isMinimized()) win.restore();
    win?.focus();
  });

  createWindow()
})

app.on('will-quit', () => {
  globalShortcut.unregisterAll()
})

import { ipcRenderer, contextBridge, desktopCapturer } from 'electron'

// --------- Expose some API to the Renderer process ---------
contextBridge.exposeInMainWorld('ipcRenderer', {
  on(...args: Parameters<typeof ipcRenderer.on>) {
    const [channel, listener] = args
    const subscription = (event: any, ...args: any[]) => listener(event, ...args)
    ipcRenderer.on(channel, subscription)
    return () => {
      ipcRenderer.removeListener(channel, subscription)
    }
  },
  off(...args: Parameters<typeof ipcRenderer.off>) {
    const [channel, ...omit] = args
    return ipcRenderer.off(channel, ...omit)
  },
  send(...args: Parameters<typeof ipcRenderer.send>) {
    const [channel, ...omit] = args
    return ipcRenderer.send(channel, ...omit)
  },
  invoke(...args: Parameters<typeof ipcRenderer.invoke>) {
    const [channel, ...omit] = args
    return ipcRenderer.invoke(channel, ...omit)
  },

  // You can expose other APTs you need here.
  // ...
})

// Expose desktopCapturer for system audio capture
contextBridge.exposeInMainWorld('desktopCapturer', {
  getSources: (opts: Electron.SourcesOptions) => desktopCapturer.getSources(opts)
})
